// Extract and validate incoming lead payload
const lead = $input.first().json.body;

// Required field validation
const requiredFields = ['customer_name', 'phone', 'city', 'service_type', 'property_type', 'issue_description'];
const missing = requiredFields.filter(f => !lead[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Default values for optional fields
lead.source = lead.source || 'Website';
lead.status = 'NEW';
lead.lead_score = lead.lead_score || 50;
lead.priority = lead.priority || 'MEDIUM';
lead.lead_quality = lead.lead_quality || 'MEDIUM';
lead.urgency = lead.urgency || 'NORMAL';
lead.estimated_job_value = lead.estimated_job_value || 'MEDIUM';
lead.customer_intent = lead.customer_intent || 'UNKNOWN';
lead.recommended_response_time = lead.recommended_response_time || 'Within 24 Hours';
lead.service_category = lead.service_category || 'General';
lead.summary = lead.summary || lead.issue_description.substring(0, 200);
lead.recommended_action = lead.recommended_action || 'Review and contact customer.';

return lead;

// Log successful ingestion
const insertedLead = $input.first().json;
const log = {
  workflow: 'Lead Ingestion',
  action: 'lead_created',
  lead_id: insertedLead.id,
  customer: insertedLead.customer_name,
  status: 'success',
  timestamp: new Date().toISOString()
};
console.log('[LEAD INGESTION]', JSON.stringify(log));
return { success: true, lead_id: insertedLead.id };

// Log failed ingestion
const error = $input.first().json.error || 'Unknown error';
const log = {
  workflow: 'Lead Ingestion',
  action: 'lead_creation_failed',
  error: error.message || error,
  status: 'failed',
  timestamp: new Date().toISOString()
};
console.error('[LEAD INGESTION ERROR]', JSON.stringify(log));
return { success: false, error: error.message || error };

// Trigger AI analysis after successful ingestion
// This node signals the ai-lead-analysis workflow
const leadId = $input.first().json.lead_id;
console.log('[LEAD INGESTION] Triggering AI analysis for lead:', leadId);
return { trigger_ai_analysis: true, lead_id: leadId };
